import{_ as r,o as t,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"12. Transfer Of Business","description":"","frontmatter":{"title":"12. Transfer Of Business","eba":"Biomedical Engineers 2025-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/preliminary/12-transfer-of-business.md","filePath":"ebas/biomedical-engineers/preliminary/12-transfer-of-business.md"}'),o={name:"ebas/biomedical-engineers/preliminary/12-transfer-of-business.md"};function a(i,e,p,l,c,f){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_12-transfer-of-business" tabindex="-1">12. Transfer Of Business <a class="header-anchor" href="#_12-transfer-of-business" aria-label="Permalink to &quot;12. Transfer Of Business&quot;">​</a></h1><p><strong>12.1</strong> Maintenance of Public Sector Employment</p><p><strong>(a)</strong> Those covered by the Agreement acknowledge the preference of public sector work continuing to be performed by the public sector.</p><p><strong>(b)</strong> However, from time to time, an Employer may determine to transfer responsibility for the delivery of existing ancillary services to a private provider.</p><p><strong>(c)</strong> The Victorian Government’s policy with respect to transfer of functions to a private provider are set out in the Public Sector Industrial Relations Policies 2015. The Employer will ensure Employee entitlements on transfer are subject to the six (6) principles contained therein. The policy as at the time this Agreement comes into operation applies to Employers and Employees but does not form part of this Agreement.</p><p><strong>12.2</strong> Employee Entitlements</p><p><strong>(a)</strong> Where the business of the employer is, before or after the date of the Agreement, transferred from the employer (in this clause 12 called the Transferor) to another employer (in this clause 12 called the Transferee) and an employee who at the time of such transfer was an employee of the Transferor in that business becomes an employee of the Transferee:</p><p><strong>(i)</strong> the continuity of the employment of the employee will be deemed not to have been broken by reason of such transfer; and</p><p><strong>(ii)</strong> the period of employment which the employee has had with the Transferor or any prior transferor will be deemed to be service of the employee with the Transferee; save that where the Transferor pays out accrued annual leave and/or long service leave to the employee upon the employee ceasing to be employed by them, this accrued annual leave and/or long service leave is not transferred to the Transferee.</p><p><strong>(b)</strong> In this clause 12:</p><p><strong>(i)</strong> business includes trade, process, business or occupation and includes any</p><p><strong>(ii)</strong> transfer includes transmission, conveyance, assignment or succession whether by agreement or by operation of law and transferred has a corresponding meaning.</p><p>RESOLUTION AND DISCIPLINE</p>',13)])])}const d=r(o,[["render",a]]);export{h as __pageData,d as default};
